import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, ForecastResult } from "../types";

const apiKey = process.env.API_KEY;
const ai = new GoogleGenAI({ apiKey: apiKey });

const analysisSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    profile: {
      type: Type.OBJECT,
      properties: {
        name: { type: Type.STRING },
        ticker: { type: Type.STRING },
        sector: { type: Type.STRING },
        description: { type: Type.STRING },
        ceo: { type: Type.STRING },
        headquarters: { type: Type.STRING },
        founded: { type: Type.STRING },
        website: { type: Type.STRING },
      },
      required: ["name", "ticker", "sector", "description", "website"],
    },
    metrics: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          label: { type: Type.STRING },
          value: { type: Type.STRING },
          change: { type: Type.NUMBER },
          trend: { type: Type.STRING, enum: ["up", "down", "neutral"] },
        },
        required: ["label", "value", "change", "trend"],
      },
    },
    chartData: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          date: { type: Type.STRING },
          revenue: { type: Type.NUMBER },
          profit: { type: Type.NUMBER },
          stockPrice: { type: Type.NUMBER },
        },
        required: ["date", "revenue", "profit", "stockPrice"],
      },
    },
    swot: {
      type: Type.OBJECT,
      properties: {
        strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
        weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
        opportunities: { type: Type.ARRAY, items: { type: Type.STRING } },
        threats: { type: Type.ARRAY, items: { type: Type.STRING } },
      },
      required: ["strengths", "weaknesses", "opportunities", "threats"],
    },
    competitors: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          marketShare: { type: Type.STRING },
          marketShareTrend: { type: Type.STRING, enum: ["up", "down", "stable"] },
          advantage: { type: Type.STRING },
          recentFunding: { type: Type.STRING },
          lastEarningsReport: { type: Type.STRING },
        },
        required: ["name", "marketShare", "marketShareTrend", "advantage"],
      },
    },
    recentNews: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          source: { type: Type.STRING },
          sentiment: { type: Type.STRING, enum: ["positive", "negative", "neutral"] },
          summary: { type: Type.STRING },
        },
        required: ["title", "source", "sentiment", "summary"],
      },
    },
    executiveSummary: { type: Type.STRING },
  },
  required: ["profile", "metrics", "chartData", "swot", "competitors", "recentNews", "executiveSummary"],
};

const forecastSchema: Schema = {
    type: Type.OBJECT,
    properties: {
        companyName: { type: Type.STRING },
        chartData: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    date: { type: Type.STRING },
                    optimistic: { type: Type.NUMBER },
                    neutral: { type: Type.NUMBER },
                    pessimistic: { type: Type.NUMBER }
                },
                required: ["date", "optimistic", "neutral", "pessimistic"]
            }
        },
        analysis: { type: Type.STRING }
    },
    required: ["companyName", "chartData", "analysis"]
};

export const analyzeCompany = async (companyName: string): Promise<AnalysisResult> => {
  if (!apiKey) throw new Error("API Key missing.");

  try {
    const model = "gemini-3-flash-preview";
    const prompt = `
      Act as a Lead Financial Analyst. Produce a complete real-time intelligence briefing for "${companyName}".
      Use Google Search to verify latest fiscal reports, news, and stock prices.
      Return JSON only.

      Schema: ${JSON.stringify(analysisSchema)}
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: { tools: [{ googleSearch: {} }], responseMimeType: "application/json" },
    });

    const data = JSON.parse(response.text) as AnalysisResult;
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    data.sourceUrls = [...new Set(groundingChunks?.map(c => c.web?.uri).filter(Boolean) as string[])];

    return data;
  } catch (error: any) {
    console.error(error);
    throw new Error(error.message || "Analysis failure.");
  }
};

export const generateForecast = async (companyName: string): Promise<ForecastResult> => {
    if (!apiKey) throw new Error("API Key missing.");

    try {
        const model = "gemini-3-flash-preview";
        const prompt = `
            Forecast 12-month stock price scenarios for "${companyName}". 
            Include optimistic, base, and pessimistic outcomes.
            Return JSON only.

            Schema: ${JSON.stringify(forecastSchema)}
        `;

        const response = await ai.models.generateContent({
            model: model,
            contents: prompt,
            config: { tools: [{ googleSearch: {} }], responseMimeType: "application/json" }
        });

        return JSON.parse(response.text) as ForecastResult;
    } catch (error: any) {
        console.error(error);
        throw new Error("Forecast engine offline.");
    }
};

import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { authService } from '../services/authService';
import { UserCircleIcon, EnvelopeIcon, PhoneIcon, MapPinIcon, BriefcaseIcon, ChevronLeftIcon } from './Icons';

interface AccountProps {
  user: User;
  onUpdateUser: (user: User) => void;
  onBack: () => void;
}

export const Account: React.FC<AccountProps> = ({ user, onUpdateUser, onBack }) => {
  const [formData, setFormData] = useState<User>(user);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  // Sync state if user prop updates externally
  useEffect(() => {
    setFormData(user);
  }, [user]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);

    try {
      if (!formData.name.trim()) throw new Error("Name is required");
      if (!formData.email.trim()) throw new Error("Email is required");

      const updatedUser = await authService.updateProfile(formData);
      onUpdateUser(updatedUser);
      setMessage({ type: 'success', text: 'Profile updated successfully.' });
    } catch (err: any) {
      setMessage({ type: 'error', text: err.message || 'Failed to update profile.' });
    } finally {
      setLoading(false);
    }
  };

  // Generate Initials
  const initials = user.name
    .split(' ')
    .map(n => n[0])
    .join('')
    .toUpperCase()
    .substring(0, 2);

  return (
    <div className="max-w-4xl mx-auto pb-20 animate-fade-in">
      <div className="mb-8 border-b border-slate-800 pb-6 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <button 
            onClick={onBack}
            className="flex items-center gap-2 text-primary-400 hover:text-white transition-colors text-sm font-bold uppercase tracking-widest mb-4 group"
          >
            <ChevronLeftIcon className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
            Back to Workspace
          </button>
          <h1 className="text-3xl font-bold text-white tracking-tight">Account Settings</h1>
          <p className="text-slate-400 mt-2">Manage your personal information and contact details.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Column: Profile Card */}
        <div className="lg:col-span-1">
           <div className="bg-slate-800 rounded-xl border border-slate-700 p-6 flex flex-col items-center text-center">
              <div className="w-24 h-24 rounded-full bg-gradient-to-tr from-primary-500 to-indigo-600 flex items-center justify-center text-3xl font-bold text-white shadow-lg mb-4">
                  {initials}
              </div>
              <h2 className="text-xl font-bold text-white">{user.name}</h2>
              <p className="text-slate-400 text-sm mt-1">{user.email}</p>

              <div className="mt-6 w-full space-y-4 text-left">
                  <div className="flex items-center gap-3 text-sm text-slate-300 bg-slate-900/50 p-3 rounded-lg border border-slate-700/50">
                      <BriefcaseIcon className="w-5 h-5 text-indigo-400" />
                      <span>{user.jobTitle || 'Role not set'}</span>
                  </div>
                  <div className="flex items-center gap-3 text-sm text-slate-300 bg-slate-900/50 p-3 rounded-lg border border-slate-700/50">
                      <MapPinIcon className="w-5 h-5 text-emerald-400" />
                      <span>{user.address || 'Location not set'}</span>
                  </div>
              </div>
           </div>
        </div>

        {/* Right Column: Edit Form */}
        <div className="lg:col-span-2">
            <div className="bg-slate-800 rounded-xl border border-slate-700 p-6">
                <h3 className="text-lg font-semibold text-white mb-6 flex items-center gap-2">
                    <UserCircleIcon className="w-5 h-5 text-primary-400" />
                    Personal Details
                </h3>

                {message && (
                    <div className={`mb-6 p-4 rounded-lg border ${message.type === 'success' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-red-500/10 border-red-500/20 text-red-400'}`}>
                        {message.text}
                    </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-2">
                            <label className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Full Name</label>
                            <div className="relative">
                                <UserCircleIcon className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
                                <input 
                                    type="text" 
                                    name="name"
                                    value={formData.name}
                                    onChange={handleChange}
                                    className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-white focus:outline-none focus:border-primary-500 focus:ring-1 focus:ring-primary-500 transition-all"
                                    required
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Job Title / Role</label>
                            <div className="relative">
                                <BriefcaseIcon className="absolute left-3 top-3 w-5 h-5 text-slate-500 pointer-events-none" />
                                <select 
                                    name="jobTitle"
                                    value={formData.jobTitle || ''}
                                    onChange={handleChange}
                                    className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-10 py-2.5 text-white focus:outline-none focus:border-primary-500 focus:ring-1 focus:ring-primary-500 transition-all appearance-none"
                                >
                                    <option value="" disabled>Select your role</option>
                                    <option value="Student">Student</option>
                                    <option value="Staff">Staff</option>
                                    <option value="Investor">Investor</option>
                                    <option value="Analyst">Analyst</option>
                                    <option value="Executive">Executive</option>
                                    <option value="Founder">Founder</option>
                                    <option value="Other">Other</option>
                                </select>
                                <div className="absolute inset-y-0 right-0 flex items-center px-3 pointer-events-none text-slate-500">
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Email Address</label>
                        <div className="relative">
                            <EnvelopeIcon className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
                            <input 
                                type="email" 
                                name="email"
                                value={formData.email}
                                onChange={handleChange}
                                className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-white focus:outline-none focus:border-primary-500 focus:ring-1 focus:ring-primary-500 transition-all"
                                required
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-2">
                            <label className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Phone Number</label>
                            <div className="relative">
                                <PhoneIcon className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
                                <input 
                                    type="tel" 
                                    name="phone"
                                    value={formData.phone || ''}
                                    onChange={handleChange}
                                    placeholder="+1 (555) 000-0000"
                                    className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-white focus:outline-none focus:border-primary-500 focus:ring-1 focus:ring-primary-500 transition-all"
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Address / Location</label>
                            <div className="relative">
                                <MapPinIcon className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
                                <input 
                                    type="text" 
                                    name="address"
                                    value={formData.address || ''}
                                    onChange={handleChange}
                                    placeholder="New York, USA"
                                    className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-white focus:outline-none focus:border-primary-500 focus:ring-1 focus:ring-primary-500 transition-all"
                                />
                            </div>
                        </div>
                    </div>

                    <div className="pt-4 flex justify-end">
                        <button 
                            type="submit" 
                            disabled={loading}
                            className="bg-primary-600 hover:bg-primary-500 text-white font-medium py-2.5 px-6 rounded-lg shadow-lg shadow-primary-900/30 transition-all transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                        >
                            {loading ? (
                                <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                            ) : 'Save Changes'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
      </div>
    </div>
  );
};

