         placeholder="Notes on strategic implications, entry points, etc..."
         value={note}
         onChange={(e) => setNote(e.target.value)}
         onBlur={handleSave} 
       />
       <p className="text-[10px] text-slate-600 mt-3 italic text-right">Auto-saved to local session</p>
    </div>
  );
}

