        ))}
      </div>

      {/* SWOT & Competitors */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        <div className="xl:col-span-2 space-y-8">
           <div className="flex flex-col md:flex-row items-center justify-between gap-6">
