const forecastSchema = {
    type: Type.OBJECT,
    properties: {
        companyName: { type: Type.STRING },
        chartData: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    date: { type: Type.STRING },
                    optimistic: { type: Type.NUMBER },
                    neutral: { type: Type.NUMBER },
                    pessimistic: { type: Type.NUMBER }
                },
                required: ["date", "optimistic", "neutral", "pessimistic"]
            }
        },
        analysis: { type: Type.STRING }
    },
    required: ["companyName", "chartData", "analysis"]
};

export const analyzeCompany = async (companyName: string): Promise<AnalysisResult> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Perform Lead Financial Analysis on "${companyName}". Extract historical fiscal metrics and perform SWOT. Use Google Search to verify real-time data. Output JSON.`,
      config: { 
        tools: [{ googleSearch: {} }], 
        responseMimeType: "application/json",
        responseSchema: analysisSchema
      },
    });

    const data = JSON.parse(response.text) as AnalysisResult;
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    data.sourceUrls = [...new Set(groundingChunks?.map(c => c.web?.uri).filter(Boolean) as string[])];
    return data;
  } catch (error: any) {
    console.error('Gemini Analysis Error:', error);
    throw new Error(error.message || "Financial analysis engine failed.");
  }
};

export const generateForecast = async (companyName: string): Promise<ForecastResult> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Predict 12-month stock price scenarios (Optimistic, Neutral, Pessimistic) for "${companyName}". Use real-time data. Output JSON.`,
            config: { 
              tools: [{ googleSearch: {} }], 
              responseMimeType: "application/json",
              responseSchema: forecastSchema
            }
        });
        return JSON.parse(response.text) as ForecastResult;
    } catch (error: any) {
        console.error('Gemini Forecast Error:', error);
        throw new Error("AI forecast engine currently offline.");
    }
};

