                    onKeyDown={handleKeyDown}
                    placeholder="Search global stocks or companies..."
                    className="relative w-full bg-slate-900/80 border border-slate-800 rounded-2xl px-6 py-5 text-white text-lg focus:outline-none focus:ring-2 focus:ring-primary-400/50 shadow-2xl transition-all backdrop-blur-md"
                  />
                  <button onClick={() => handleSearch()} className="absolute right-3 top-3 bottom-3 px-8 bg-gradient-to-r from-primary-400 to-primary-600 hover:from-primary-500 hover:to-primary-400 text-slate-950 rounded-xl font-black uppercase tracking-widest text-xs transition-all flex items-center gap-2 active:scale-95 shadow-lg">
                    <SearchIcon className="w-4 h-4" /> Analyze
